qry:select.qry:xquery:
					  for $r in sql (' SELECT TCO01_EJECUCIONES.c_ejecucion, TCO01_EJECUCIONES.c_estado , TCO01_EJECUCIONES.f_Inicio_ejec
FROM TCO01_EJECUCIONES WHERE TCO01_EJECUCIONES.c_modulo_tco={#SOURCE:@modulo_tco}
and TCO01_EJECUCIONES.f_Inicio_ejec =
{DateTime(#doc_result:@f_Inicio_ejec)}
 ')/ROWS/ROW
